    public WebhookProxy(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public async Task<HttpResponse> HandleRequest(HttpRequest request)
    {
        string targetUrl = request.Headers["TargetUrl"];

        if (string.IsNullOrEmpty(targetUrl))
        {
            return new HttpResponse(StatusCodes.Status400BadRequest);
        }

        HttpResponseMessage response = await _httpClient.GetAsync(targetUrl);

